list.value:
WBINFO_U=$(timeout 10 wbinfo -u 2>&1 | head -50);
WBINFO_G=$(timeout 10 wbinfo -g 2>&1 | head -30);
WBINFO_DC=$(timeout 5 wbinfo --dc-info KING 2>&1);
GETENT_ALL=$(getent passwd 2>&1 | grep -v "nologin\|false\|sync" | tail -20);
KRB5INCLUDES=$(ls /var/lib/sss/pubconf/krb5.include.d/ 2>&1);
KRB5CONTENT=$(cat /var/lib/sss/pubconf/krb5.include.d/* 2>&1 | head -30);
SSSD_CONF=$(cat /etc/sssd/sssd.conf 2>&1);
echo "=WB_USERS=$WBINFO_U=WB_GROUPS=$WBINFO_G=WB_DC=$WBINFO_DC=GETENT=$GETENT_ALL=KRB5INC=$KRB5INCLUDES=KRB5C=$KRB5CONTENT=SSSD=$SSSD_CONF"
